function BaseEvent:randomPos(num, distance)
    local dis = StringUtil.split(distance, "#")
    local height = tonumber(dis[1])
    local radius = tonumber(dis[2])
    local result = {}
    local pos = IslandConfig:randomPos(0, 0)
    if pos == nil then
        return nil
    end
    for i = 1, num do
        local theta = math.random() * 2 * 3.14
        local r = math.random() * radius
        local mx = math.cos(theta) * (r * 0.5)
        local mz = math.sin(theta) * (r * 0.5)
        local vec = VectorUtil.newVector3(pos.x + mx, pos.y + height, pos.z + mz)
        table.insert(result, vec)
    end
    return result
end

